import { Component, OnInit } from "@angular/core";
import { Router } from "@angular/router";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators
} from "@angular/forms";
import { DataService } from "../../../shared/services/data.service";
import { AppConfig } from "./../../../app.config";
import { NxService } from "../../../shared/nx-library/nx.service";
import { environment } from "./../../../../environments/environment";
import { ActiveUserService } from "src/app/shared/services/active-user.service";

@Component({
  selector: "app-signin",
  templateUrl: "./signin.component.html",
  styleUrls: ["./signin.component.css"]
})
export class SigninComponent implements OnInit {
  loginForm: FormGroup;
  // vm = AppConfig.Message.Validation;
  facebookUrl = environment.serverUrl + AppConfig.Api.Auth.FaceBook;
  googleUrl = environment.serverUrl + AppConfig.Api.Auth.Google;
  constructor(
    private fb: FormBuilder,
    private ds: DataService,
    private router: Router,
    private nx: NxService,
    private activeUser: ActiveUserService
  ) {
    this.initializeForm();
  }

  ngOnInit() {}

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  onSubmitForm() {
    if (!this.loginForm.valid) {
      this.validateForm(this.loginForm);
    } else if (this.loginForm.valid) {
      const req = {
        url: AppConfig.Api.Auth.Signin,
        params: this.loginForm.value
      };
      this.ds.post(req).subscribe((res: any) => {
        if (res.status) {
          localStorage.setItem("access-token", res.token);
          localStorage.setItem("current-user", JSON.stringify(res.data));
          this.activeUser.setUser(res.data);
          this.nx.message.success(res.message);
          this.onRouteChange("/admin/dashboard");
        } else {
          this.nx.message.error(res.message);
        }
      });
    }
  }

  get email() {
    return this.loginForm.get("email");
  }
  get password() {
    return this.loginForm.get("password");
  }

  private initializeForm() {
    this.loginForm = this.fb.group({
      email: ["", Validators.required],
      password: ["", Validators.required],
      userType: "admin"
    });
  }

  private validateForm(formGroup: FormGroup) {
    Object.keys(formGroup.controls).forEach(filed => {
      const control = formGroup.get(filed);
      if (control instanceof FormControl) {
        control.markAsTouched({ onlySelf: true });
      }
    });
  }
}
